#include "jayess_runtime.h"

#include <ctype.h>
#include <stdlib.h>
#include <string.h>

typedef struct jayess_css_parser {
    const char *input;
    size_t length;
    size_t pos;
    const char *error;
} jayess_css_parser;

typedef struct jayess_css_buffer {
    char *data;
    size_t length;
    size_t capacity;
    int failed;
} jayess_css_buffer;

typedef struct jayess_css_position {
    size_t offset;
    int line;
    int column;
} jayess_css_position;

static void jayess_css_fail(jayess_css_parser *parser, const char *message) {
    if (parser->error == NULL) {
        parser->error = message;
    }
}

static int jayess_css_peek(jayess_css_parser *parser) {
    if (parser->pos >= parser->length) {
        return -1;
    }
    return (unsigned char) parser->input[parser->pos];
}

static int jayess_css_has_prefix(jayess_css_parser *parser, const char *text) {
    size_t prefix_length = strlen(text);
    if (parser->pos + prefix_length > parser->length) {
        return 0;
    }
    return strncmp(parser->input + parser->pos, text, prefix_length) == 0;
}

static void jayess_css_skip_ws(jayess_css_parser *parser) {
    while (parser->pos < parser->length && isspace((unsigned char) parser->input[parser->pos])) {
        parser->pos++;
    }
}

static char *jayess_css_copy_range(const char *input, size_t start, size_t end) {
    size_t length = end > start ? end - start : 0;
    char *text = (char *) malloc(length + 1);
    if (text == NULL) {
        return NULL;
    }
    if (length > 0) {
        memcpy(text, input + start, length);
    }
    text[length] = '\0';
    return text;
}

static char *jayess_css_strdup(const char *text) {
    size_t length;
    char *copy;
    if (text == NULL) {
        return NULL;
    }
    length = strlen(text);
    copy = (char *) malloc(length + 1);
    if (copy == NULL) {
        return NULL;
    }
    memcpy(copy, text, length + 1);
    return copy;
}

static char *jayess_css_trim_copy(const char *input, size_t start, size_t end) {
    while (start < end && isspace((unsigned char) input[start])) {
        start++;
    }
    while (end > start && isspace((unsigned char) input[end - 1])) {
        end--;
    }
    return jayess_css_copy_range(input, start, end);
}

static void jayess_css_free_partial_array(jayess_array *array) {
    if (array != NULL) {
        jayess_array_free_unshared(array);
    }
}

static int jayess_css_is_ident_start(int ch) {
    return isalpha((unsigned char) ch) || ch == '_' || ch == '-';
}

static int jayess_css_is_ident_char(int ch) {
    return jayess_css_is_ident_start(ch) || isdigit((unsigned char) ch);
}

static char *jayess_css_parse_ident(jayess_css_parser *parser) {
    size_t start = parser->pos;
    if (!jayess_css_is_ident_start(jayess_css_peek(parser))) {
        return NULL;
    }
    parser->pos++;
    while (parser->pos < parser->length && jayess_css_is_ident_char((unsigned char) parser->input[parser->pos])) {
        parser->pos++;
    }
    return jayess_css_copy_range(parser->input, start, parser->pos);
}

static jayess_css_position jayess_css_position_for(jayess_css_parser *parser, size_t offset) {
    jayess_css_position position;
    size_t index;
    position.offset = offset;
    position.line = 1;
    position.column = 1;
    for (index = 0; index < offset && index < parser->length; index++) {
        if (parser->input[index] == '\n') {
            position.line++;
            position.column = 1;
        } else {
            position.column++;
        }
    }
    return position;
}

static jayess_value *jayess_css_position_value(jayess_css_position position) {
    jayess_object *value = jayess_object_new();
    jayess_object_set_value(value, "offset", jayess_value_from_number((double) position.offset));
    jayess_object_set_value(value, "line", jayess_value_from_number((double) position.line));
    jayess_object_set_value(value, "column", jayess_value_from_number((double) position.column));
    return jayess_value_from_object(value);
}

static void jayess_css_set_span(jayess_value *node, jayess_css_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_object *span = jayess_object_new();
    jayess_object_set_value(span, "start", jayess_css_position_value(jayess_css_position_for(parser, start_offset)));
    jayess_object_set_value(span, "end", jayess_css_position_value(jayess_css_position_for(parser, end_offset)));
    jayess_value_set_member(node, "span", jayess_value_from_object(span));
}

static jayess_value *jayess_css_make_token(const char *type, const char *value, jayess_css_parser *parser, size_t start_offset, size_t end_offset) {
    jayess_object *token = jayess_object_new();
    jayess_object_set_value(token, "type", jayess_value_from_string(type));
    jayess_object_set_value(token, "value", jayess_value_from_string(value != NULL ? value : ""));
    jayess_object_set_value(token, "span", jayess_value_undefined());
    {
        jayess_value *token_value = jayess_value_from_object(token);
        jayess_css_set_span(token_value, parser, start_offset, end_offset);
        return token_value;
    }
}

static jayess_value *jayess_css_make_stylesheet(jayess_array *rules) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("stylesheet"));
    jayess_object_set_value(node, "rules", jayess_value_from_array(rules));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_css_make_comment(const char *value) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("comment"));
    jayess_object_set_value(node, "value", jayess_value_from_string(value != NULL ? value : ""));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_css_make_declaration(const char *property, const char *value, jayess_array *value_parts) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("declaration"));
    jayess_object_set_value(node, "property", jayess_value_from_string(property != NULL ? property : ""));
    jayess_object_set_value(node, "value", jayess_value_from_string(value != NULL ? value : ""));
    jayess_object_set_value(node, "valueParts", jayess_value_from_array(value_parts));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_css_make_rule(const char *selector, jayess_array *selector_tokens, jayess_array *declarations) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("rule"));
    jayess_object_set_value(node, "selector", jayess_value_from_string(selector != NULL ? selector : ""));
    jayess_object_set_value(node, "selectorTokens", jayess_value_from_array(selector_tokens));
    jayess_object_set_value(node, "declarations", jayess_value_from_array(declarations));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_value *jayess_css_make_at_rule(const char *name, const char *prelude, jayess_array *prelude_tokens, jayess_array *rules) {
    jayess_object *node = jayess_object_new();
    jayess_object_set_value(node, "type", jayess_value_from_string("atRule"));
    jayess_object_set_value(node, "name", jayess_value_from_string(name != NULL ? name : ""));
    jayess_object_set_value(node, "prelude", jayess_value_from_string(prelude != NULL ? prelude : ""));
    jayess_object_set_value(node, "preludeTokens", jayess_value_from_array(prelude_tokens));
    jayess_object_set_value(node, "rules", jayess_value_from_array(rules));
    jayess_object_set_value(node, "span", jayess_value_undefined());
    return jayess_value_from_object(node);
}

static jayess_array *jayess_css_tokenize_fragment(const char *input, size_t offset_base);
static jayess_value *jayess_css_parse_rule(jayess_css_parser *parser);

static jayess_array *jayess_css_tokenize_value_parts(const char *input, size_t offset_base) {
    return jayess_css_tokenize_fragment(input, offset_base);
}

static jayess_array *jayess_css_tokenize_fragment(const char *input, size_t offset_base) {
    jayess_css_parser parser;
    jayess_array *tokens = jayess_array_new();
    parser.input = input;
    parser.length = strlen(input);
    parser.pos = 0;
    parser.error = NULL;
    while (parser.pos < parser.length) {
        size_t start = parser.pos;
        int ch = jayess_css_peek(&parser);
        if (isspace((unsigned char) ch)) {
            parser.pos++;
            continue;
        }
        if (jayess_css_has_prefix(&parser, "/*")) {
            size_t value_start;
            size_t value_end;
            char *comment;
            parser.pos += 2;
            value_start = parser.pos;
            while (parser.pos + 1 < parser.length && !jayess_css_has_prefix(&parser, "*/")) {
                parser.pos++;
            }
            if (!jayess_css_has_prefix(&parser, "*/")) {
                break;
            }
            value_end = parser.pos;
            comment = jayess_css_copy_range(parser.input, value_start, value_end);
            parser.pos += 2;
            jayess_array_push_value(tokens, jayess_css_make_token("comment", comment != NULL ? comment : "", &parser, offset_base + start, offset_base + parser.pos));
            free(comment);
            continue;
        }
        if (ch == '"' || ch == '\'') {
            int quote = ch;
            char *text;
            parser.pos++;
            while (parser.pos < parser.length && parser.input[parser.pos] != quote) {
                parser.pos++;
            }
            if (parser.pos >= parser.length) {
                break;
            }
            text = jayess_css_copy_range(parser.input, start + 1, parser.pos);
            parser.pos++;
            jayess_array_push_value(tokens, jayess_css_make_token("string", text != NULL ? text : "", &parser, offset_base + start, offset_base + parser.pos));
            free(text);
            continue;
        }
        if (ch == '@') {
            char *name;
            parser.pos++;
            name = jayess_css_parse_ident(&parser);
            if (name == NULL) {
                jayess_array_push_value(tokens, jayess_css_make_token("punctuation", "@", &parser, offset_base + start, offset_base + parser.pos));
            } else {
                jayess_array_push_value(tokens, jayess_css_make_token("atKeyword", name, &parser, offset_base + start, offset_base + parser.pos));
                free(name);
            }
            continue;
        }
        if (isdigit((unsigned char) ch) || (ch == '.' && parser.pos + 1 < parser.length && isdigit((unsigned char) parser.input[parser.pos + 1]))) {
            size_t number_start = parser.pos;
            char *number_text;
            char *unit_text;
            while (parser.pos < parser.length && (isdigit((unsigned char) parser.input[parser.pos]) || parser.input[parser.pos] == '.')) {
                parser.pos++;
            }
            number_text = jayess_css_copy_range(parser.input, number_start, parser.pos);
            if (parser.pos < parser.length && jayess_css_is_ident_start((unsigned char) parser.input[parser.pos])) {
                size_t unit_start = parser.pos;
                while (parser.pos < parser.length && jayess_css_is_ident_char((unsigned char) parser.input[parser.pos])) {
                    parser.pos++;
                }
                unit_text = jayess_css_copy_range(parser.input, unit_start, parser.pos);
                {
                    size_t total_length = strlen(number_text != NULL ? number_text : "") + strlen(unit_text != NULL ? unit_text : "") + 1;
                    char *dimension = (char *) malloc(total_length);
                    if (dimension != NULL) {
                        strcpy(dimension, number_text != NULL ? number_text : "");
                        strcat(dimension, unit_text != NULL ? unit_text : "");
                        jayess_array_push_value(tokens, jayess_css_make_token("dimension", dimension, &parser, offset_base + start, offset_base + parser.pos));
                        free(dimension);
                    }
                }
                free(unit_text);
            } else {
                jayess_array_push_value(tokens, jayess_css_make_token("number", number_text != NULL ? number_text : "", &parser, offset_base + start, offset_base + parser.pos));
            }
            free(number_text);
            continue;
        }
        if (jayess_css_is_ident_start(ch)) {
            char *name = jayess_css_parse_ident(&parser);
            jayess_array_push_value(tokens, jayess_css_make_token("ident", name != NULL ? name : "", &parser, offset_base + start, offset_base + parser.pos));
            free(name);
            continue;
        }
        if (strchr("{}:;,.#>()[]", ch) != NULL) {
            char punct[2];
            punct[0] = (char) ch;
            punct[1] = '\0';
            parser.pos++;
            jayess_array_push_value(tokens, jayess_css_make_token("punctuation", punct, &parser, offset_base + start, offset_base + parser.pos));
            continue;
        }
        {
            char delim[2];
            delim[0] = (char) ch;
            delim[1] = '\0';
            parser.pos++;
            jayess_array_push_value(tokens, jayess_css_make_token("delimiter", delim, &parser, offset_base + start, offset_base + parser.pos));
        }
    }
    return tokens;
}

static jayess_value *jayess_css_parse_comment_node(jayess_css_parser *parser) {
    size_t start = parser->pos;
    size_t value_start;
    size_t value_end;
    char *value;
    parser->pos += 2;
    value_start = parser->pos;
    while (parser->pos + 1 < parser->length && !jayess_css_has_prefix(parser, "*/")) {
        parser->pos++;
    }
    if (!jayess_css_has_prefix(parser, "*/")) {
        jayess_css_fail(parser, "unterminated CSS comment");
        return jayess_value_undefined();
    }
    value_end = parser->pos;
    value = jayess_css_copy_range(parser->input, value_start, value_end);
    parser->pos += 2;
    {
        jayess_value *node = jayess_css_make_comment(value != NULL ? value : "");
        jayess_css_set_span(node, parser, start, parser->pos);
        free(value);
        return node;
    }
}

static jayess_value *jayess_css_parse_at_rule(jayess_css_parser *parser) {
    size_t start = parser->pos;
    char *name;
    char *prelude;
    jayess_array *prelude_tokens;
    jayess_array *rules = jayess_array_new();
    parser->pos++;
    name = jayess_css_parse_ident(parser);
    if (name == NULL) {
        jayess_css_free_partial_array(rules);
        jayess_css_fail(parser, "expected CSS at-rule name");
        return jayess_value_undefined();
    }
    {
        size_t prelude_start = parser->pos;
        while (parser->pos < parser->length && jayess_css_peek(parser) != ';' && jayess_css_peek(parser) != '{') {
            parser->pos++;
        }
        prelude = jayess_css_trim_copy(parser->input, prelude_start, parser->pos);
        prelude_tokens = jayess_css_tokenize_fragment(prelude != NULL ? prelude : "", prelude_start);
    }
    if (strcmp(name, "import") == 0) {
        if (jayess_css_peek(parser) != ';') {
            jayess_css_free_partial_array(prelude_tokens);
            jayess_css_free_partial_array(rules);
            free(name);
            free(prelude);
            jayess_css_fail(parser, "expected ; after CSS @import");
            return jayess_value_undefined();
        }
        parser->pos++;
        {
            jayess_value *node = jayess_css_make_at_rule(name, prelude != NULL ? prelude : "", prelude_tokens, rules);
            jayess_css_set_span(node, parser, start, parser->pos);
            free(name);
            free(prelude);
            return node;
        }
    }
    if (strcmp(name, "media") == 0) {
        if (jayess_css_peek(parser) != '{') {
            jayess_css_free_partial_array(prelude_tokens);
            jayess_css_free_partial_array(rules);
            free(name);
            free(prelude);
            jayess_css_fail(parser, "expected { after CSS @media prelude");
            return jayess_value_undefined();
        }
        parser->pos++;
        while (parser->pos < parser->length) {
            jayess_css_skip_ws(parser);
            if (jayess_css_has_prefix(parser, "/*")) {
                jayess_array_push_value(rules, jayess_css_parse_comment_node(parser));
                if (parser->error != NULL || jayess_has_exception()) {
                    jayess_css_free_partial_array(prelude_tokens);
                    jayess_css_free_partial_array(rules);
                    free(name);
                    free(prelude);
                    return jayess_value_undefined();
                }
                continue;
            }
            if (jayess_css_peek(parser) == '}') {
                parser->pos++;
                {
                    jayess_value *node = jayess_css_make_at_rule(name, prelude != NULL ? prelude : "", prelude_tokens, rules);
                    jayess_css_set_span(node, parser, start, parser->pos);
                    free(name);
                    free(prelude);
                    return node;
                }
            }
            if (jayess_css_peek(parser) == '@') {
                jayess_css_free_partial_array(prelude_tokens);
                jayess_css_free_partial_array(rules);
                free(name);
                free(prelude);
                jayess_css_fail(parser, "nested CSS at-rules are not supported on the current parser path");
                return jayess_value_undefined();
            }
            jayess_array_push_value(rules, jayess_css_parse_rule(parser));
            if (parser->error != NULL || jayess_has_exception()) {
                jayess_css_free_partial_array(prelude_tokens);
                jayess_css_free_partial_array(rules);
                free(name);
                free(prelude);
                return jayess_value_undefined();
            }
        }
        jayess_css_free_partial_array(prelude_tokens);
        jayess_css_free_partial_array(rules);
        free(name);
        free(prelude);
        jayess_css_fail(parser, "unterminated CSS @media block");
        return jayess_value_undefined();
    }
    jayess_css_free_partial_array(prelude_tokens);
    jayess_css_free_partial_array(rules);
    free(name);
    free(prelude);
    jayess_css_fail(parser, "CSS at-rule is not supported on the current parser path");
    return jayess_value_undefined();
}

static jayess_value *jayess_css_parse_declaration(jayess_css_parser *parser) {
    size_t start = parser->pos;
    char *property;
    char *value;
    jayess_array *value_parts;
    size_t value_start;
    size_t value_end;
    property = jayess_css_parse_ident(parser);
    if (property == NULL) {
        jayess_css_fail(parser, "expected CSS property name");
        return jayess_value_undefined();
    }
    jayess_css_skip_ws(parser);
    if (jayess_css_peek(parser) != ':') {
        free(property);
        jayess_css_fail(parser, "expected : after CSS property");
        return jayess_value_undefined();
    }
    parser->pos++;
    value_start = parser->pos;
    while (parser->pos < parser->length && jayess_css_peek(parser) != ';' && jayess_css_peek(parser) != '}') {
        if (jayess_css_has_prefix(parser, "/*")) {
            break;
        }
        parser->pos++;
    }
    value_end = parser->pos;
    value = jayess_css_trim_copy(parser->input, value_start, value_end);
    value_parts = jayess_css_tokenize_value_parts(value != NULL ? value : "", value_start);
    {
        jayess_value *node = jayess_css_make_declaration(property, value != NULL ? value : "", value_parts);
        jayess_css_set_span(node, parser, start, value_end);
        free(property);
        free(value);
        return node;
    }
}

static jayess_value *jayess_css_parse_rule(jayess_css_parser *parser) {
    size_t start = parser->pos;
    size_t selector_start = parser->pos;
    size_t selector_end;
    char *selector;
    jayess_array *selector_tokens;
    jayess_array *declarations = jayess_array_new();
    while (parser->pos < parser->length && jayess_css_peek(parser) != '{') {
        if (jayess_css_has_prefix(parser, "/*")) {
            jayess_css_free_partial_array(declarations);
            jayess_css_fail(parser, "comments are not allowed inside CSS selectors on the current parser path");
            return jayess_value_undefined();
        }
        parser->pos++;
    }
    if (jayess_css_peek(parser) != '{') {
        jayess_css_free_partial_array(declarations);
        jayess_css_fail(parser, "expected { after CSS selector");
        return jayess_value_undefined();
    }
    selector_end = parser->pos;
    selector = jayess_css_trim_copy(parser->input, selector_start, selector_end);
    selector_tokens = jayess_css_tokenize_fragment(selector != NULL ? selector : "", selector_start);
    parser->pos++;
    while (parser->pos < parser->length) {
        jayess_css_skip_ws(parser);
        if (jayess_css_has_prefix(parser, "/*")) {
            jayess_array_push_value(declarations, jayess_css_parse_comment_node(parser));
            if (parser->error != NULL || jayess_has_exception()) {
                jayess_css_free_partial_array(selector_tokens);
                jayess_css_free_partial_array(declarations);
                free(selector);
                return jayess_value_undefined();
            }
            continue;
        }
        if (jayess_css_peek(parser) == '}') {
            parser->pos++;
            break;
        }
        if (jayess_css_peek(parser) == '@') {
            jayess_css_free_partial_array(selector_tokens);
            jayess_css_free_partial_array(declarations);
            free(selector);
            jayess_css_fail(parser, "nested CSS at-rules are not supported inside style rules");
            return jayess_value_undefined();
        }
        jayess_array_push_value(declarations, jayess_css_parse_declaration(parser));
        if (parser->error != NULL || jayess_has_exception()) {
            jayess_css_free_partial_array(selector_tokens);
            jayess_css_free_partial_array(declarations);
            free(selector);
            return jayess_value_undefined();
        }
        jayess_css_skip_ws(parser);
        if (jayess_css_peek(parser) == ';') {
            parser->pos++;
        }
    }
    {
        jayess_value *node = jayess_css_make_rule(selector != NULL ? selector : "", selector_tokens, declarations);
        jayess_css_set_span(node, parser, start, parser->pos);
        free(selector);
        return node;
    }
}

jayess_value *jayess_css_tokenize(jayess_value *input_value) {
    const char *input = jayess_expect_string(input_value, "jayess_css_tokenize");
    char *owned_input;
    jayess_value *result;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    owned_input = jayess_css_strdup(input);
    if (owned_input == NULL) {
        return jayess_value_undefined();
    }
    result = jayess_value_from_array(jayess_css_tokenize_fragment(owned_input, 0));
    free(owned_input);
    return result;
}

jayess_value *jayess_css_parse_stylesheet(jayess_value *input_value) {
    const char *input = jayess_expect_string(input_value, "jayess_css_parse_stylesheet");
    char *owned_input;
    jayess_css_parser parser;
    jayess_array *rules;
    if (jayess_has_exception()) {
        return jayess_value_undefined();
    }
    owned_input = jayess_css_strdup(input);
    if (owned_input == NULL) {
        return jayess_value_undefined();
    }
    parser.input = owned_input;
    parser.length = strlen(input);
    parser.pos = 0;
    parser.error = NULL;
    rules = jayess_array_new();
    while (parser.pos < parser.length) {
        jayess_css_skip_ws(&parser);
        if (parser.pos >= parser.length) {
            break;
        }
        if (jayess_css_has_prefix(&parser, "/*")) {
            jayess_array_push_value(rules, jayess_css_parse_comment_node(&parser));
            if (parser.error != NULL || jayess_has_exception()) {
                break;
            }
            continue;
        }
        if (jayess_css_peek(&parser) == '@') {
            jayess_array_push_value(rules, jayess_css_parse_at_rule(&parser));
            if (parser.error != NULL || jayess_has_exception()) {
                break;
            }
            continue;
        }
        jayess_array_push_value(rules, jayess_css_parse_rule(&parser));
        if (parser.error != NULL || jayess_has_exception()) {
            break;
        }
    }
    if (parser.error != NULL) {
        jayess_css_free_partial_array(rules);
        free(owned_input);
        jayess_throw_named_error("CSSParseError", parser.error);
        return jayess_value_undefined();
    }
    {
        jayess_value *stylesheet = jayess_css_make_stylesheet(rules);
        jayess_css_set_span(stylesheet, &parser, 0, parser.pos);
        free(owned_input);
        return stylesheet;
    }
}

static void jayess_css_buffer_append_bytes(jayess_css_buffer *buffer, const char *text, size_t length) {
    size_t required;
    char *grown;
    if (buffer->failed || text == NULL || length == 0) {
        return;
    }
    required = buffer->length + length + 1;
    if (required > buffer->capacity) {
        size_t next_capacity = buffer->capacity == 0 ? 64 : buffer->capacity;
        while (next_capacity < required) {
            next_capacity *= 2;
        }
        grown = (char *) realloc(buffer->data, next_capacity);
        if (grown == NULL) {
            buffer->failed = 1;
            return;
        }
        buffer->data = grown;
        buffer->capacity = next_capacity;
    }
    memcpy(buffer->data + buffer->length, text, length);
    buffer->length += length;
    buffer->data[buffer->length] = '\0';
}

static void jayess_css_buffer_append_cstr(jayess_css_buffer *buffer, const char *text) {
    if (text != NULL) {
        jayess_css_buffer_append_bytes(buffer, text, strlen(text));
    }
}

static int jayess_css_serialize_preserve_comments(jayess_value *options) {
    jayess_value *comments_value;
    if (options == NULL || jayess_value_kind_of(options) == JAYESS_VALUE_UNDEFINED || jayess_value_kind_of(options) == JAYESS_VALUE_NULL) {
        return 1;
    }
    comments_value = jayess_value_get_member(options, "comments");
    if (comments_value == NULL || jayess_value_kind_of(comments_value) == JAYESS_VALUE_UNDEFINED) {
        return 1;
    }
    return jayess_value_as_bool(comments_value);
}

static int jayess_css_serialize_pretty(jayess_value *options) {
    jayess_value *pretty_value;
    if (options == NULL || jayess_value_kind_of(options) == JAYESS_VALUE_UNDEFINED || jayess_value_kind_of(options) == JAYESS_VALUE_NULL) {
        return 0;
    }
    pretty_value = jayess_value_get_member(options, "pretty");
    if (pretty_value == NULL || jayess_value_kind_of(pretty_value) == JAYESS_VALUE_UNDEFINED) {
        return 0;
    }
    return jayess_value_as_bool(pretty_value);
}

static int jayess_css_serialize_minify(jayess_value *options) {
    jayess_value *minify_value;
    if (options == NULL || jayess_value_kind_of(options) == JAYESS_VALUE_UNDEFINED || jayess_value_kind_of(options) == JAYESS_VALUE_NULL) {
        return 0;
    }
    minify_value = jayess_value_get_member(options, "minify");
    if (minify_value == NULL || jayess_value_kind_of(minify_value) == JAYESS_VALUE_UNDEFINED) {
        return 0;
    }
    return jayess_value_as_bool(minify_value);
}

static void jayess_css_buffer_indent(jayess_css_buffer *buffer, int depth) {
    int index;
    for (index = 0; index < depth; index++) {
        jayess_css_buffer_append_cstr(buffer, "  ");
    }
}

static void jayess_css_serialize_value(jayess_value *node, jayess_css_buffer *buffer, int preserve_comments, int pretty, int depth);

static void jayess_css_serialize_value(jayess_value *node, jayess_css_buffer *buffer, int preserve_comments, int pretty, int depth) {
    const char *type = jayess_value_as_string(jayess_value_get_member(node, "type"));
    if (type == NULL || buffer->failed) {
        return;
    }
    if (strcmp(type, "stylesheet") == 0) {
        jayess_array *rules = jayess_value_as_array(jayess_value_get_member(node, "rules"));
        int index;
        if (rules == NULL) {
            return;
        }
        for (index = 0; index < jayess_array_length(rules); index++) {
            jayess_css_serialize_value(jayess_array_get(rules, index), buffer, preserve_comments, pretty, depth);
        }
        return;
    }
    if (strcmp(type, "comment") == 0) {
        if (!preserve_comments) {
            return;
        }
        jayess_css_buffer_append_cstr(buffer, "/*");
        jayess_css_buffer_append_cstr(buffer, jayess_value_as_string(jayess_value_get_member(node, "value")));
        jayess_css_buffer_append_cstr(buffer, "*/");
        return;
    }
    if (strcmp(type, "rule") == 0) {
        jayess_array *declarations = jayess_value_as_array(jayess_value_get_member(node, "declarations"));
        int index;
        jayess_css_buffer_append_cstr(buffer, jayess_value_as_string(jayess_value_get_member(node, "selector")));
        jayess_css_buffer_append_cstr(buffer, "{");
        if (declarations != NULL) {
            for (index = 0; index < jayess_array_length(declarations); index++) {
                jayess_value *declaration = jayess_array_get(declarations, index);
                const char *decl_type = jayess_value_as_string(jayess_value_get_member(declaration, "type"));
                if (decl_type != NULL && strcmp(decl_type, "comment") == 0) {
                    if (pretty && preserve_comments) {
                        jayess_css_buffer_append_cstr(buffer, "\n");
                        jayess_css_buffer_indent(buffer, depth + 1);
                    }
                    jayess_css_serialize_value(declaration, buffer, preserve_comments, pretty, depth + 1);
                    continue;
                }
                if (pretty) {
                    jayess_css_buffer_append_cstr(buffer, "\n");
                    jayess_css_buffer_indent(buffer, depth + 1);
                }
                jayess_css_buffer_append_cstr(buffer, jayess_value_as_string(jayess_value_get_member(declaration, "property")));
                jayess_css_buffer_append_cstr(buffer, ":");
                if (pretty) {
                    jayess_css_buffer_append_cstr(buffer, " ");
                }
                jayess_css_buffer_append_cstr(buffer, jayess_value_as_string(jayess_value_get_member(declaration, "value")));
                jayess_css_buffer_append_cstr(buffer, ";");
            }
        }
        if (pretty && declarations != NULL && jayess_array_length(declarations) > 0) {
            jayess_css_buffer_append_cstr(buffer, "\n");
            jayess_css_buffer_indent(buffer, depth);
        }
        jayess_css_buffer_append_cstr(buffer, "}");
        return;
    }
    if (strcmp(type, "atRule") == 0) {
        const char *name = jayess_value_as_string(jayess_value_get_member(node, "name"));
        const char *prelude = jayess_value_as_string(jayess_value_get_member(node, "prelude"));
        jayess_array *rules = jayess_value_as_array(jayess_value_get_member(node, "rules"));
        int index;
        jayess_css_buffer_append_cstr(buffer, "@");
        jayess_css_buffer_append_cstr(buffer, name != NULL ? name : "");
        if (prelude != NULL && prelude[0] != '\0') {
            jayess_css_buffer_append_cstr(buffer, " ");
            jayess_css_buffer_append_cstr(buffer, prelude);
        }
        if (rules == NULL || jayess_array_length(rules) == 0) {
            jayess_css_buffer_append_cstr(buffer, ";");
            return;
        }
        jayess_css_buffer_append_cstr(buffer, "{");
        for (index = 0; index < jayess_array_length(rules); index++) {
            if (pretty) {
                jayess_css_buffer_append_cstr(buffer, "\n");
                jayess_css_buffer_indent(buffer, depth + 1);
            }
            jayess_css_serialize_value(jayess_array_get(rules, index), buffer, preserve_comments, pretty, depth + 1);
        }
        if (pretty && jayess_array_length(rules) > 0) {
            jayess_css_buffer_append_cstr(buffer, "\n");
            jayess_css_buffer_indent(buffer, depth);
        }
        jayess_css_buffer_append_cstr(buffer, "}");
    }
}

jayess_value *jayess_css_serialize(jayess_value *node, jayess_value *options) {
    jayess_css_buffer buffer;
    int preserve_comments = jayess_css_serialize_preserve_comments(options);
    int pretty = jayess_css_serialize_pretty(options);
    int minify = jayess_css_serialize_minify(options);
    if (minify) {
        pretty = 0;
    }
    buffer.data = NULL;
    buffer.length = 0;
    buffer.capacity = 0;
    buffer.failed = 0;
    jayess_css_serialize_value(node, &buffer, preserve_comments, pretty, 0);
    if (buffer.failed) {
        free(buffer.data);
        jayess_throw_named_error("CSSSerializeError", "failed to serialize CSS");
        return jayess_value_undefined();
    }
    if (buffer.data == NULL) {
        return jayess_value_from_string("");
    }
    {
        jayess_value *result = jayess_value_from_string(buffer.data);
        free(buffer.data);
        return result;
    }
}
